// Combine all inputs for Claude prompt
const calendar = $('Read Content Calendar').all().map(i => i.json);
const ideas = $('Get Content Ideas from ClickUp').first().json;
const rss = $('Fetch Industry RSS').all().map(i => i.json);

// Find this week's row in content calendar
const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - now.getDay());
const weekKey = weekStart.toLocaleDateString('en-US');

const thisWeek = calendar.find(row => {
  const rowDate = new Date(row['Week Of']);
  return Math.abs(rowDate - weekStart) < 7 * 24 * 60 * 60 * 1000;
}) || {};

// Format content ideas
const ideaList = (ideas.tasks || []).map(t => `- ${t.name}: ${t.description || ''}`).join('
') || 'No pending ideas';

// Format RSS headlines
const newsItems = rss.slice(0, 10).map(item => `- ${item.title}: ${item.link}`).join('
') || 'No recent news';

const weekOf = weekStart.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

return [{
  json: {
    system_prompt: `You are a ghostwriter for a solo RevOps consultant who works with B2B SaaS companies ($10-100M). You write LinkedIn posts that build authority, generate inbound leads, and spark conversations.

**Voice & Tone:**
- First person, conversational but knowledgeable
- Opinionated — take a stance, don't hedge everything
- Practical — every post should teach something or challenge an assumption
- Anti-corporate — no buzzword soup, no "thrilled to announce", no humble brags
- Short sentences. Punchy. Occasional one-word paragraphs for emphasis.
- Use "you" often — talk TO the reader

**Format rules:**
- Hook must stop the scroll (first 2 lines visible before "see more")
- Line breaks liberally
- 150-300 words
- End with a question or call-to-discussion
- 3-5 relevant hashtags
- No emojis in main text

**NEVER:** "I'm excited to share...", humble brags, vague motivational content, anything identifying a specific client`,
    user_prompt: `Generate 5 LinkedIn post drafts for this week.

**Week Of:** ${weekOf}
**Content Calendar Theme:** ${thisWeek['Notes'] || 'No specific theme'}
**Calendar Requirements:** Monday: ${thisWeek['Monday Topic'] || 'open'}, Wednesday: ${thisWeek['Wednesday Topic'] || 'open'}, Friday: ${thisWeek['Friday Topic'] || 'open'}

**Content Ideas Backlog:**
${ideaList}

**Industry News:**
${newsItems}

---

Generate 5 posts (2 Tactical Tips, 1 Case Study anonymized, 1 Contrarian Take, 1 Data Insight). Posts 1-3 are for Mon/Wed/Fri publishing. Posts 4-5 are backups.

For each post provide JSON with: post_number, category, hook (first 2 lines), body (full 150-300 word text), hashtags (array), publishing_notes, confidence (high/medium), alternative_hook.

Return as a JSON array of 5 post objects.`,
    model: 'gemini-free',
    workflow_name: 'linkedin-content-generator',
    client_name: 'Self',
    purpose: 'LinkedIn content generation',
    week_of: weekOf
  }
}];

// Format posts into a Google Doc for review
const response = $input.all()[0].json;
const posts = Array.isArray(response.parsed_content) ? response.parsed_content : [response.parsed_content];
const weekOf = $('Build Content Prompt').first().json.week_of;

let docContent = `# LinkedIn Drafts — Week of ${weekOf}

`;
docContent += `*Generated: ${new Date().toLocaleString()}*

---

`;

for (const post of posts) {
  docContent += `## Post ${post.post_number}: ${post.category}
`;
  docContent += `**Confidence:** ${post.confidence}

`;
  docContent += `**Hook:** ${post.hook}

`;
  docContent += `---
${post.body}

`;
  docContent += `${(post.hashtags || []).join(' ')}

`;
  docContent += `**Alt Hook:** ${post.alternative_hook}
`;
  docContent += `**Notes:** ${post.publishing_notes}

`;
  docContent += `- [ ] **APPROVED FOR PUBLISHING**

`;
  docContent += `---

`;
}

return [{ json: { doc_content: docContent, post_count: posts.length, week_of: weekOf } }];
